"use strict";function parse(e){let t=[];return{keys:t,pattern:RegExp(`${("/"===e[0]?e.slice(1):e).split("/").reduce((e,r)=>{if("*"===r)e+="/(?:.*)";else if(":"===r[0]){let s="?"===r[r.length-1];e+=s?"(?:/([^/]+?))?":"/([^/]+?)",t.push(r.slice(1,s?r.length-1:r.length))}else e+=`/${escapeRegExp(r)}`;return e})}/?$`,"i")}}function escapeRegExp(e){return e.replace(/[\\*+.?{}()[\]^$\-|/]/g,"\\$&")}exports.parse=parse;
